def tenant_create_view(request):
    """Lida com a criaГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВѕГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВѕГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В¦ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬В¦ГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г…ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В§ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВѕГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВѕГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В¦ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬В¦ГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г…ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЈo de um novo tenant."""
    if request.method == 'POST':
        form = TenantForm(request.POST, request.FILES, is_creation=True)
        if form.is_valid():
            try:
                opts = form.cleaned_data
                call_command(
                    'provisionar_tenant',
                    '--nome', opts['nome'],
                    '--slug', opts['slug'],
                    '--dominio', opts['dominio'],
                    '--razao_social', opts['razao_social'],
                    '--cnpj', opts['cnpj'],
                    '--admin-user', opts['admin_user'],
                    '--admin-email', opts['admin_email'],
                    '--admin-pass', opts['admin_pass'],
                )
                tenant = get_object_or_404(Tenant, slug=opts['slug'])
                form_for_save = TenantForm(request.POST, request.FILES, instance=tenant)
                if form_for_save.is_valid():
                    form_for_save.save()
                messages.success(request, f"Cliente '{opts['nome']}' provisionado com sucesso!")
                return redirect('control:tenant_list')
            except Exception as e:
                messages.error(request, f"Falha no provisionamento: {e}")
                # Limpeza: se o comando falhou, tenta apagar o registro do tenant que pode ter sido criado.
                Tenant.objects.filter(slug=opts.get('slug')).delete()
        else:
            messages.error(request, "Foram encontrados erros no formulГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВѕГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВѕГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В¦ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬В¦ГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г…ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЎrio. Por favor, corrija-os.")
    else:
        form = TenantForm(is_creation=True)
    context = {'form': form, 'data_page': 'tenant_form'}
    return render_ajax_or_base(request, 'partials/control/tenant_form.html', context)

@superuser_required
@principal_context_required
def tenant_edit_view(request, pk):
    """Lida com a ediГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВѕГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВѕГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В¦ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬В¦ГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г…ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В§ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВѕГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В ГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВѕГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В ГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓВўГўв‚¬ЕѕГ‚ВўГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚В¬ГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г‚В¦ГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Гўв‚¬В ГѓВўГўвЂљВ¬ГўвЂћВўГѓЖ’Г†вЂ™ГѓвЂљГ‚ВўГѓЖ’Г‚ВўГѓВўГўвЂљВ¬Г…ВЎГѓвЂљГ‚В¬ГѓЖ’Гўв‚¬В¦ГѓвЂљГ‚ВЎГѓЖ’Г†вЂ™ГѓвЂ Гўв‚¬в„ўГѓЖ’Г‚ВўГѓВўГўв‚¬ЕЎГ‚В¬ГѓвЂ¦Г‚ВЎГѓЖ’Г†вЂ™ГѓВўГўвЂљВ¬Г…ВЎГѓЖ’Гўв‚¬ЕЎГѓвЂљГ‚ВЈo de um tenant existente."""
    tenant = get_object_or_404(Tenant, pk=pk)
    if request.method == 'POST':
        form = TenantForm(request.POST, request.FILES, instance=tenant)
        if form.is_valid():
            form.save()
            messages.success(request, f"Cliente '{tenant.nome}' atualizado com sucesso!")
            return redirect('control:tenant_list')
    else:
        form = TenantForm(instance=tenant)
